import requests
import os

def main(event):
    # Extract input fields from the workflow
    deal_id = event["inputFields"]["deal_record_id"]
    ahj_id = event["inputFields"]["ahj_record_id"]

    # Object types
    from_object_type = "deal"
    to_object_type = "2-7957390"

    # Authorization
    access_token = os.environ.get('photon_association_handler')

    # Headers
    headers = {
        "Authorization": f"Bearer {access_token}",
        "Content-Type": "application/json"
    }

    # Delete association between deal and AHJ object record
    url = f"https://api.hubapi.com/crm/v4/objects/{from_object_type}/{deal_id}/associations/{to_object_type}/{ahj_id}"

    response = requests.delete(url, headers=headers)

    if response.status_code == 204:
        status = f"Association between deal {deal_id} and AHJ {ahj_id} successfully removed."
    else:
        status = f"Failed to remove association. Status code: {response.status_code}, Response: {response.text}"

    # Return status for use in the workflow
    return {
        "outputFields": {
            "status": status
        }
    }
